def evaluate_postfix(expression):
    stack = []
    operators = {'+', '-', '*', '/'}

    tokens = expression.split()

    for token in tokens:
        if token not in operators:
            try:
                stack.append(float(token))
            except ValueError:
                raise ValueError(f"Geçersiz ifade öğesi: {token}")
        else:
            if len(stack) < 2:
                raise ValueError(f"'{token}' operatörü için yeterli sayıda işlenen yok")

            operand2 = stack.pop()
            operand1 = stack.pop()

            if token == '+':
                result = operand1 + operand2
            elif token == '-':
                result = operand1 - operand2
            elif token == '*':
                result = operand1 * operand2
            elif token == '/':
                if operand2 == 0:
                    raise ZeroDivisionError("Sıfıra bölme hatası")
                result = operand1 / operand2
            else:
                raise ValueError(f"Bilinmeyen operatör: {token}")

            stack.append(result)

    if len(stack) != 1:
        raise ValueError("Geçersiz postfix ifadesi: çok fazla işlenen veya operatör")

    return stack[0]
